import React, { useEffect, useMemo, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import {
  Alert,
  Button,
  Card,
  Col,
  Container,
  Form,
  Row,
  Spinner,
} from "react-bootstrap";
import { getEventDetailWithTickets } from "../services/eventService";
import { createOrder } from "../services/orderService";

function EventDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [event, setEvent] = useState(null);
  const [ticketTypes, setTicketTypes] = useState([]);
  const [summary, setSummary] = useState(null);
  const [quantities, setQuantities] = useState({});
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  useEffect(() => {
    const fetchEventDetail = async () => {
      try {
        setLoading(true);
        setError("");

        const response = await getEventDetailWithTickets(id);

        if (response.data?.success && response.data?.data) {
          const payload = response.data.data;
          const eventData = payload.event || null;
          const ticketList = payload.ticketTypes || [];
          const summaryData = payload.summary || null;

          setEvent(eventData);
          setTicketTypes(ticketList);
          setSummary(summaryData);

          const initialQuantities = {};
          ticketList.forEach((ticket) => {
            initialQuantities[ticket.id] = 0;
          });
          setQuantities(initialQuantities);
        } else {
          setError("Không lấy được chi tiết sự kiện");
        }
      } catch (err) {
        console.error("Lỗi tải chi tiết sự kiện:", err);
        setError(
          err.response?.data?.message || "Lỗi khi tải chi tiết sự kiện"
        );
      } finally {
        setLoading(false);
      }
    };

    fetchEventDetail();
  }, [id]);

  const getBannerSrc = (bannerImage) => {
    if (!bannerImage) {
      return "https://via.placeholder.com/1200x700?text=Concert+Banner";
    }

    if (
      bannerImage.startsWith("http://") ||
      bannerImage.startsWith("https://")
    ) {
      return bannerImage;
    }

    return `/images/${bannerImage}`;
  };

  const formatDateTime = (dateString) => {
    if (!dateString) return "Không có dữ liệu";
    const date = new Date(dateString);

    return date.toLocaleString("vi-VN", {
      weekday: "long",
      year: "numeric",
      month: "long",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    });
  };

  const getEventStatusText = (status) => {
    switch (status) {
      case "draft":
        return "Nháp";
      case "upcoming":
        return "Sắp mở bán";
      case "on_sale":
        return "Đang mở bán";
      case "paused":
        return "Tạm dừng";
      case "sold_out":
        return "Hết vé";
      case "ended":
        return "Đã kết thúc";
      case "cancelled":
        return "Đã hủy";
      default:
        return status || "Không xác định";
    }
  };

  const handleQuantityChange = (ticket, value) => {
    let quantity = Number(value);

    if (Number.isNaN(quantity) || quantity < 0) quantity = 0;

    const maxAllowed = Math.min(
      Number(ticket.available || 0),
      Number(ticket.max_per_order || 0)
    );

    if (quantity > maxAllowed) quantity = maxAllowed;

    setQuantities((prev) => ({
      ...prev,
      [ticket.id]: quantity,
    }));
  };

  const totalTickets = useMemo(() => {
    return ticketTypes.reduce((sum, ticket) => {
      return sum + Number(quantities[ticket.id] || 0);
    }, 0);
  }, [ticketTypes, quantities]);

  const totalAmount = useMemo(() => {
    return ticketTypes.reduce((sum, ticket) => {
      const qty = Number(quantities[ticket.id] || 0);
      return sum + qty * Number(ticket.price || 0);
    }, 0);
  }, [ticketTypes, quantities]);

  const canBuy = ticketTypes.some(
    (ticket) =>
      Number(ticket.available || 0) > 0 && Number(ticket.max_per_order || 0) > 0
  );

  const handleCreateOrder = async () => {
    try {
      setError("");
      setSuccess("");

      const token = localStorage.getItem("token");
      if (!token) {
        navigate("/login");
        return;
      }

      const items = ticketTypes
        .filter((ticket) => Number(quantities[ticket.id] || 0) > 0)
        .map((ticket) => ({
          ticket_type_id: ticket.id,
          quantity: Number(quantities[ticket.id]),
        }));

      if (items.length === 0) {
        setError("Vui lòng chọn ít nhất 1 vé");
        return;
      }

      setSubmitting(true);

      const response = await createOrder(items);

     if (response.data?.success) {
  const orderId = response.data.data?.orderId;

  setSuccess("Đặt vé thành công, chuyển sang trang thanh toán...");

  setTimeout(() => {
    navigate(`/payment/${orderId}`);
  }, 800);
} else {
        setError(response.data?.message || "Đặt vé thất bại");
      }
    } catch (err) {
      console.error("Lỗi tạo đơn hàng:", err);
      setError(err.response?.data?.message || "Đã xảy ra lỗi khi đặt vé");
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div
        className="d-flex justify-content-center align-items-center"
        style={{ minHeight: "70vh" }}
      >
        <Spinner animation="border" variant="dark" />
      </div>
    );
  }

  if (error && !event) {
    return (
      <Container className="py-5 text-center">
        <h3>{error}</h3>
      </Container>
    );
  }

  if (!event) {
    return (
      <Container className="py-5 text-center">
        <h3>Rất tiếc, không tìm thấy sự kiện này.</h3>
      </Container>
    );
  }

  return (
    <Container fluid className="py-4 px-lg-5" style={{ background: "#f6f7fb" }}>
      <Row className="justify-content-center">
        <Col xl={11}>
          {error && <Alert variant="danger">{error}</Alert>}
          {success && <Alert variant="success">{success}</Alert>}

          <Card className="shadow-sm border-0 mb-4 overflow-hidden">
            <Row className="g-0">
              <Col md={7}>
                <img
                  src={getBannerSrc(event.banner_image)}
                  alt={event.title}
                  style={{
                    width: "100%",
                    height: "100%",
                    minHeight: "360px",
                    objectFit: "cover",
                  }}
                  onError={(e) => {
                    e.target.src =
                      "https://via.placeholder.com/1200x700?text=Concert+Banner";
                  }}
                />
              </Col>

              <Col md={5}>
                <div className="p-4 h-100 d-flex flex-column justify-content-between">
                  <div>
                    <div
                      style={{
                        display: "inline-block",
                        padding: "6px 12px",
                        borderRadius: "999px",
                        background: "#111827",
                        color: "#fff",
                        fontSize: "14px",
                        marginBottom: "16px",
                      }}
                    >
                      {getEventStatusText(event.status)}
                    </div>

                    <h1 style={{ fontSize: "2rem", fontWeight: 700 }}>
                      {event.title}
                    </h1>

                    <p style={{ color: "#6b7280", marginTop: "16px" }}>
                      {event.description || "Không có mô tả"}
                    </p>

                    <div className="mt-4">
                      <p className="mb-2">
                        <strong>Địa điểm:</strong> {event.location}
                      </p>
                      <p className="mb-2">
                        <strong>Thời gian:</strong> {formatDateTime(event.event_date)}
                      </p>
                      <p className="mb-2">
                        <strong>Mở check-in:</strong>{" "}
                        {formatDateTime(event.checkin_start_time)}
                      </p>
                      <p className="mb-2">
                        <strong>Đóng check-in:</strong>{" "}
                        {formatDateTime(event.checkin_end_time)}
                      </p>
                      <p className="mb-0">
                        <strong>Tổng loại vé:</strong> {ticketTypes.length}
                      </p>
                    </div>
                  </div>

                  {summary && (
                    <div
                      className="mt-4"
                      style={{
                        background: "#f9fafb",
                        borderRadius: "12px",
                        padding: "16px",
                      }}
                    >
                      <div className="d-flex justify-content-between mb-2">
                        <span>Tổng số lượng vé</span>
                        <strong>{summary.totalQuantity ?? 0}</strong>
                      </div>
                      <div className="d-flex justify-content-between mb-2">
                        <span>Đã bán</span>
                        <strong>{summary.totalSold ?? 0}</strong>
                      </div>
                      <div className="d-flex justify-content-between">
                        <span>Còn lại</span>
                        <strong>{summary.totalAvailable ?? 0}</strong>
                      </div>
                    </div>
                  )}
                </div>
              </Col>
            </Row>
          </Card>

          <Row className="g-4">
            <Col lg={7}>
              <Card className="shadow-sm border-0">
                <Card.Body className="p-4">
                  <h3 className="mb-4">Chọn loại vé</h3>

                  {ticketTypes.length === 0 ? (
                    <Alert variant="warning">
                      Hiện chưa có loại vé cho sự kiện này.
                    </Alert>
                  ) : (
                    ticketTypes.map((ticket) => {
                      const maxAllowed = Math.min(
                        Number(ticket.available || 0),
                        Number(ticket.max_per_order || 0)
                      );

                      return (
                        <Card key={ticket.id} className="mb-3 border">
                          <Card.Body>
                            <Row className="align-items-center">
                              <Col md={8}>
                                <h5 className="mb-2">{ticket.name}</h5>
                                <p className="text-muted mb-2">
                                  {ticket.description || "Không có mô tả"}
                                </p>
                                <div className="mb-1">
                                  <strong>Giá:</strong>{" "}
                                  {Number(ticket.price || 0).toLocaleString("vi-VN")} VND
                                </div>
                                <div className="mb-1">
                                  <strong>Còn lại:</strong> {ticket.available ?? 0}
                                </div>
                                <div className="mb-1">
                                  <strong>Tối đa mỗi đơn:</strong>{" "}
                                  {ticket.max_per_order ?? 0}
                                </div>
                                <div>
                                  <strong>Chuyển nhượng:</strong>{" "}
                                  {Number(ticket.transferable) === 1 ? "Có" : "Không"}
                                </div>
                              </Col>

                              <Col md={4}>
                                <Form.Group>
                                  <Form.Label>Số lượng</Form.Label>
                                  <Form.Control
                                    type="number"
                                    min={0}
                                    max={maxAllowed}
                                    value={quantities[ticket.id] || 0}
                                    onChange={(e) =>
                                      handleQuantityChange(ticket, e.target.value)
                                    }
                                    disabled={maxAllowed <= 0}
                                  />
                                </Form.Group>
                              </Col>
                            </Row>
                          </Card.Body>
                        </Card>
                      );
                    })
                  )}
                </Card.Body>
              </Card>
            </Col>

            <Col lg={5}>
              <Card
                className="shadow-sm border-0"
                style={{ position: "sticky", top: "100px" }}
              >
                <Card.Body className="p-4">
                  <h3 className="mb-4">Tóm tắt đơn hàng</h3>

                  <div className="d-flex justify-content-between mb-2">
                    <span>Tổng số vé</span>
                    <strong>{totalTickets}</strong>
                  </div>

                  <div className="d-flex justify-content-between mb-3">
                    <span>Tổng tiền</span>
                    <strong>
                      {totalAmount.toLocaleString("vi-VN")} VND
                    </strong>
                  </div>

                  <Button
                    variant="dark"
                    className="w-100"
                    disabled={!canBuy || totalTickets === 0 || submitting}
                    onClick={handleCreateOrder}
                  >
                    {submitting ? "Đang đặt vé..." : "MUA VÉ NGAY"}
                  </Button>
                </Card.Body>
              </Card>a
            </Col>
          </Row>
        </Col>
      </Row>
    </Container>
  );
}

export default EventDetailPage;
